import Foundation

struct TierTemplate {
    let name: String
    let category: String
    let items: [TemplateItem]
    
    struct TemplateItem {
        let name: String
        let imageURL: URL
    }
}

extension TierTemplate {
    /// Unique category names in alphabetical order for the main menu.
    static var allCategories: [String] {
        let categories = Set(all.map(\.category))
        return categories.sorted()
    }

    /// All templates whose category matches the given name.
    static func templates(forCategory category: String) -> [TierTemplate] {
        all.filter { $0.category == category }
    }

